# Tracking override rates for calibration monitoring
from collections import defaultdict
import statistics

class OverrideTracker:
    def __init__(self):
        self.records = []

    def log_decision(self, ai_recommendation, human_decision, ground_truth=None):
        override = ai_recommendation != human_decision
        record = {
            'ai_rec': ai_recommendation,
            'human': human_decision,
            'override': override,
        }
        if ground_truth is not None:
            record['correct'] = human_decision == ground_truth
            record['ai_correct'] = ai_recommendation == ground_truth
        self.records.append(record)

    def override_rate(self):
        return sum(r['override'] for r in self.records) / max(len(self.records), 1)

    def override_accuracy(self):
        # When human overrides, are they more often correct or less?
        overrides = [r for r in self.records if r['override'] and 'correct' in r]
        if not overrides: return None
        return sum(r['correct'] for r in overrides) / len(overrides)

# override_rate() near 0 -> potential complacency
# override_accuracy() near 1 -> human correctly catching AI errors
# override_accuracy() near 0 -> human overriding correct AI (underreliance)

import numpy as np
from dataclasses import dataclass
from typing import List

@dataclass
class Trial:
    question_id: int
    ai_correct: bool       # ground truth
    ai_shown: bool         # whether AI suggestion was displayed
    user_correct: bool     # user's final answer

def overreliance_index(trials: List[Trial]) -> float:
    """
    Proportion of AI-error trials where user also erred.
    Perfect score = 0 (user always catches AI mistakes).
    """
    ai_error_trials = [t for t in trials if t.ai_shown and not t.ai_correct]
    if not ai_error_trials:
        return float('nan')
    also_wrong = sum(1 for t in ai_error_trials if not t.user_correct)
    return also_wrong / len(ai_error_trials)

def underreliance_index(trials: List[Trial]) -> float:
    """
    Proportion of AI-correct trials where user overrode to wrong answer.
    """
    ai_correct_trials = [t for t in trials if t.ai_shown and t.ai_correct]
    if not ai_correct_trials:
        return float('nan')
    override_wrong = sum(1 for t in ai_correct_trials if not t.user_correct)
    return override_wrong / len(ai_correct_trials)

# Example usage
np.random.seed(42)
n = 200
trials = [
    Trial(
        question_id=i,
        ai_correct=(np.random.rand() < 0.85),
        ai_shown=True,
        user_correct=(np.random.rand() < 0.75),
    )
    for i in range(n)
]
print(f'Overreliance index:  {overreliance_index(trials):.2f}')
print(f'Underreliance index: {underreliance_index(trials):.2f}')

# Adaptive scepticism nudge: increase friction when overreliance is detected
class OverrelianceGuard:
    def __init__(self, flip_rate_threshold=0.6, window=20):
        self.threshold = flip_rate_threshold
        self.window = window
        self.history = []  # (user_initial, user_final, ai_suggestion)

    def record(self, user_initial, user_final, ai_suggestion):
        flipped_to_ai = (user_initial != ai_suggestion) and (user_final == ai_suggestion)
        self.history.append(flipped_to_ai)
        if len(self.history) > self.window:
            self.history.pop(0)

    @property
    def flip_rate(self):
        if not self.history:
            return 0.0
        return sum(self.history) / len(self.history)

    def should_nudge(self) -> bool:
        return len(self.history) >= self.window and self.flip_rate > self.threshold

    def nudge_message(self) -> str:
        if self.should_nudge():
            return (f'Notice: you have agreed with the AI on {self.flip_rate:.0%} of '
                    'recent decisions where you initially disagreed. Take a moment to '
                    'verify this answer independently.')
        return ''
